* {
    box-sizing: border-box;
}

.carrous-section {
    padding: 60px 20px;
}

.carrous-container {
    max-width: 1100px;
    margin: auto;
    overflow: hidden;
}

.carrous-track {
    display: flex;
    transition: transform 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

/* Desktop → 3 cards */
.carrous-card {
    flex: 0 0 calc(100% / 3);
    padding: 8px;
}

.card-inner {
    background: #fff;
    border: 2px solid;
    height: 100%;
    display: flex;
    flex-direction: column;
}

.card-header {
    color: #fff;
    padding: 14px 16px;
    font-weight: 700;
    font-size: 13px;
    letter-spacing: 0.5px;
    text-transform: uppercase;
    line-height: 1.3;
    min-height: 56px;
    display: flex;
    align-items: center;
}

.card-inner img {
    width: 100%;
    height: 200px;
    object-fit: cover;
    display: block;
}

.card-body {
    padding: 16px;
    font-size: 13.5px;
    color: #333;
    line-height: 1.6;
    flex: 1;
}

.card-body ul {
    margin-top: 10px;
    padding-left: 0;
    list-style: none;
}

.card-body ul li::before {
    content: "• ";
}

/* Colors */
.orange .card-inner  { border-color: #e8891a; }
.orange .card-header { background: #e8891a; }

.pink .card-inner    { border-color: #c0175e; }
.pink .card-header   { background: #c0175e; }

.purple .card-inner  { border-color: #8B3FA8; }
.purple .card-header { background: #8B3FA8; }

/* Navigation */
.carrous-nav {
    text-align: center;
    margin-top: 24px;
}

.carrous-prev,
.carrous-next {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    border: 2px solid #555;
    background: #fff;
    cursor: pointer;
    font-size: 22px;
    line-height: 1;
    margin: 0 5px;
    transition: background 0.2s, color 0.2s;
    color: #333;
}

.carrous-prev:hover,
.carrous-next:hover {
    background: #333;
    color: #fff;
}

/* Tablet → 2 cards */
@media (max-width: 1024px) and (min-width: 581px) {
    .carrous-card { flex: 0 0 50%; }
}

/* Mobile → 1 card */
@media (max-width: 580px) {
    .carrous-card { flex: 0 0 100%; }
}
